        Timer: function (ResponseTime, ResolveTime) {
            var vueObj = this;

            // Fallback like ASP.NET version
            var responseTime = ResponseTime || vueObj.ResponseTime;
            var resolveTime = ResolveTime || vueObj.ResolveTime;

            var showResponse = "1";
            if (responseTime == undefined || responseTime == "0") {
                showResponse = "0";
            }

            var showResolve = "1";
            if (resolveTime == undefined || resolveTime == "0") {
                showResolve = "0";
            }

            var showSLA = "yes";

            // Call StartTimer (Vue version without display/ctrl)
            vueObj.StartTimer(responseTime, resolveTime, showResponse, showResolve, showSLA);

            // Optional: keep tooltip logic if using jQuery/Bootstrap
            // if (/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent) == false) {
            //     if (window.$ && $.fn.tooltip) {
            //         $('[data-toggle="tooltip"]').tooltip();
            //     }
            // }
        },
        StartTimer: function (responseTime, resolveTime, showResponse, showResolve, SLA_Value) {
            var vueObj = this;

            var durationResponseTime = 0;
            var durationResolveTime = 0;

            if (showResponse == "1") {
                durationResponseTime = responseTime;
            }
            if (showResolve == "1") {
                durationResolveTime = resolveTime;
            }

            if (showResponse == "1" || showResolve == "1") {

                if (vueObj._timer) {
                    clearInterval(vueObj._timer);
                }

                var negativeResponseTime = false;
                var negativeResolveTime = false;

                var timerResponseTime = durationResponseTime;
                var timerResolveTime = durationResolveTime;

                vueObj._timer = setInterval(function () {

                    if (SLA_Value.toLowerCase() == "no") {
                        vueObj.ResponseTime = "--";
                        vueObj.ResolveTime = "--";
                        return;
                    }

                    // RESPONSE TIME
                    if (timerResponseTime < 0) {
                        timerResponseTime = -timerResponseTime;
                        negativeResponseTime = true;
                    }

                    if (timerResponseTime != undefined && timerResponseTime != "0" && timerResponseTime != "") {

                        var mins_num = parseFloat(timerResponseTime, 10);
                        var hours = Math.floor(mins_num / 60);
                        var minutes = Math.floor((mins_num - ((hours * 3600)) / 60));
                        var seconds = Math.floor((mins_num * 60) - (hours * 3600) - (minutes * 60));

                        hours = hours < 10 ? "0" + hours : hours;
                        minutes = minutes < 10 ? "0" + minutes : minutes;
                        seconds = seconds < 10 ? "0" + seconds : seconds;

                        if (negativeResponseTime) {
                            vueObj.ResponseTime = "-" + hours + ":" + minutes + ":" + seconds;
                            timerResponseTime += 1 / 60;
                        } else {
                            vueObj.ResponseTime = hours + ":" + minutes + ":" + seconds;
                            timerResponseTime -= 1 / 60;

                            if (timerResponseTime < 0) {
                                negativeResponseTime = true;
                            }
                        }
                    } else {
                        vueObj.ResponseTime = "00:00:00";
                    }

                    // RESOLVE TIME
                    if (timerResolveTime < 0) {
                        timerResolveTime = -timerResolveTime;
                        negativeResolveTime = true;
                    }

                    if (timerResolveTime != undefined && timerResolveTime != "0" && timerResolveTime != "") {

                        var mins_num_resolve_time = parseFloat(timerResolveTime, 10);
                        var hours_resolve_time = Math.floor(mins_num_resolve_time / 60);
                        var minutes_resolve_time = Math.floor((mins_num_resolve_time - ((hours_resolve_time * 3600)) / 60));
                        var seconds_resolve_time = Math.floor((mins_num_resolve_time * 60) - (hours_resolve_time * 3600) - (minutes_resolve_time * 60));

                        hours_resolve_time = hours_resolve_time < 10 ? "0" + hours_resolve_time : hours_resolve_time;
                        minutes_resolve_time = minutes_resolve_time < 10 ? "0" + minutes_resolve_time : minutes_resolve_time;
                        seconds_resolve_time = seconds_resolve_time < 10 ? "0" + seconds_resolve_time : seconds_resolve_time;

                        if (negativeResolveTime) {
                            vueObj.ResolveTime = "-" + hours_resolve_time + ":" + minutes_resolve_time + ":" + seconds_resolve_time;
                            timerResolveTime += 1 / 60;
                        } else {
                            vueObj.ResolveTime = hours_resolve_time + ":" + minutes_resolve_time + ":" + seconds_resolve_time;
                            timerResolveTime -= 1 / 60;

                            if (timerResolveTime < 0) {
                                negativeResolveTime = true;
                            }
                        }
                    } else {
                        vueObj.ResolveTime = "00:00:00";
                    }

                }, 1000);

            } else {
                vueObj.ResponseTime = "--";
                vueObj.ResolveTime = "--";
            }
