        Close: function () {
            var vm = this;
            vm.isMoreTicketDetail = false;
        },
        showTicketDetail: function () {
            var vm = this;
            vm.isMoreTicketDetail = true;
            vm.isTicketDetail = true;
            vm.isTicketText = false;
            vm.LeftViewData = vm.TicketDetailDataForPopup;

