        //     debugger
        //     this.OpenWindow('https://app.talygen.com/Communication/Index?reqhFrom=40348', 800, 1200, false);
        // },
        OpenChat: function (parameter) {
            let url = 'https://app.talygen.com/Communication/Index?reqhFrom=40348';

            switch (parameter) {
                case 'Call':
                    url += '&Call=true';
                    break;
                case 'VideoCall':
                    url += '&VideoCall=true';
                    break;
                case 'Message':
                    url += '&Message=true';
                    break;
                case 'Chat':
                    url += '&Chat=true';
                    break;                
            }

            this.OpenWindow(url, 800, 1200, false);
        },
        OpenWindow: function (query, h, w, scroll) {
            var isMobile;
            var chatlogwindow;
            if (isMobile == true) {
                localStorage.removeItem('clientOpen');
            }

            var screenWidth = window.innerWidth * 0.7;
            var screenHeight = window.innerHeight * 0.8;

            var l = (window.innerWidth - screenWidth) / 2;
            var t = (window.innerHeight - screenHeight) / 3;

            var winprops = 'height=' + screenHeight + ',width=' + screenWidth + ',top=' + t + ',resizable=0,status=no,menubar=no,toolbar=no,location=no,addressbar=no,left=' + l;
            if (scroll) winprops += ',scrollbars=1';

            var stateClient = localStorage.getItem('clientOpen'); //window.localStorage.getItem

            if (stateClient == "1") {
                console.log(" localStorage.removeItem('clientOpen');");
                if (window.navigator.userAgent.indexOf("Edge") > -1) // because edge does not have local object global
                {
                    chatlogwindow = window.open(query, "_blank", winprops);
                }
            } else {
                if (isMobile == true) {
                    chatlogwindow = window.open(query, "_self", winprops);
                } else {
                    //   localStorage.setItem('clientOpen', '1');
                    chatlogwindow = window.open(query, "_blank", winprops);
                }
            }
        },
        openTicketTextTab: function () {
            var vm = this;
            vm.isMoreTicketDetail = true;
            var url = `TicketId=${this.TicketId}&formId=`;
            DataService.GetTicketText(url).then(function (response) {
                if (response.data != null && response.data.status == "Success" && response.data.result.DATA.length > 0) {
                    vm.isTicketText = true;
                    vm.isTicketDetail = false;
                    vm.TicketTextDetail = response.data.result.DATA[0].TICKETTEXT;
                }
                else if(response.data.result.DATA.length === 0){
                    vm.showTicketDetail();
                }
            });
        },

    }
