<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">{{ $t('Update') }}</h5>
                            <button v-on:click="$emit('close')" href="javascript:;" class="close">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG"
                                    role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                        class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con" v-html="$t('UgTicketingViewUpdate')"></div>
                                    </div>
                                </div>
                            </span>
                        </div>
                        <div class="modal-body">
                            <dynamic-form ref="DataLoaded" lang="en" :buttons="buttons" :schema="FormSchema"
                                v-on:OnSubmit="onSubmit">                               
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from "@/services/DataService";
export default {
    props: {
        TicketId: {
            type: String,
            required: true
        },
        modulename: {
            type: String,
            required: true
        },
        submodulecode: {
            type: String,
            required: true
        },
        callbackfunction: {
            type: Function
        }
    },
    data() {
        return {
            statusList: [],
            CCUserList: [],
            CategoryList: [],
            priorityList: [],
            productList: [],
            isSupportTicket:false,
            ccOption: [],
            popover: {
                visibility: false
            },
            isLoading: false,
            isProductChanged: 0,
            isETAChanged: 0,
            isStatusChanged: 0,
            isCategoryChanged: 0,
            isPriorityChanged: 0,
            isDelayResponse:0,
            Mainleveldiv: [],
            IsChangeData: 1,
            UserType: null,
            FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('Status'),
                            name: "Status",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeDropdown
                            },
                            validationRules: "",
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Expected Resolution (M/D/YYYY)'),
                            name: "ExpectedResolution",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                format: "M/D/YYYY",
                            },
                            popover: {
                                visibility: true
                            },                           
                            validationRules: {"required": false},
                        },
                        {
                            astype: "MultiSelectField",
                            mode: "tag",
                            label: this.$t('CC Users'),
                            name: "CCUsers",
                            disabled: false,
                            value: "",
                            config: {
                                options: []
                            },
                            placeholder: this.$t('CC Users'),
                            validationRules: { "required": false },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Ticket Category'),
                            name: "TicketCategory",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeDropdown
                            },
                            validationRules: "",
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Product'),
                            name: "Product",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeDropdown
                            },
                            validationRules: "",
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('ItemName'),
                            name: "ItemName",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeDropdown
                            },
                            validationRules: "",
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Priority'),
                            name: "Priority",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false,
                                onChange: this.onChangeDropdown
                            },
                            validationRules: "",
                        },
                        {
                            astype: "RadioField",
                            label: this.$t('Ticket Delayed'),
                            name: "IsDelay",
                            value: "0",
                            placeholder: "",
                            config: {
                                options: [{
                                    name: 'No', value: 0
                                },{
                                    name: 'Yes', value: 1
                                }],
                                showAddIcon: false,
                                onChange: this.onChangeRadio
                            },
                            validationRules: { "required": false },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Ticket Delay Response'),
                            name: "TicketDelayResponse",
                            value: "",
                            placeholder: "",
                            disabled: false,
                            config: {
                                options: [],
                                showAddIcon: false                               
                            },
                            visibility: false,
                            validationRules: { "required": true }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Update"
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close
                }
            ],
            onBehalfConsumerId: 0,
            isAssetPermission:false
        }
    },
    async created() {
        var vm = this;
        vm.GetPrivilegeData();
        vm.GetStatusList();
        vm.GetCCUserList();
        vm.GetCategoryForTicket();
        vm.GetPrioritybyCompanyId();
        vm.FetchTicketData();
        vm.UserType = vm.GetUserInfo.UserType;
    },
    methods: {
        GetPrivilegeData: function () {
            var vm = this;
            this.isBillingType = localStorage.getItem("billingType") === "USIC";
            if(this.isBillingType){
                vm.GetProductsList(true);
                vm.FormSchema[0].Data[4].visibility =true;
                vm.FormSchema[0].Data[5].visibility =false;
            }
            else
            {
                var param = 'controller=Asset&action=MyItems';
                DataService.CheckPrivilege(param).then(function (response) {
                    if (response.data) {
                        vm.isAssetPermission=true;
                        vm.GetProductsList(false);
                        vm.FormSchema[0].Data[4].visibility =true;
                        vm.FormSchema[0].Data[5].visibility =true;
                    }
                    else{
                        vm.FormSchema[0].Data[4].visibility =false;
                        vm.FormSchema[0].Data[5].visibility =false;
                        vm.isAssetPermission=false;
                    }
                })
            }
            
        },
        FetchTicketData: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `ticketId=${vm.TicketId}`;
            DataService.GetTicketById(url).then(function (response) {
                vm.isLoading = false;
                if (response.data.ticket != null) {  
                    vm.Mainleveldiv.push({ StatusId: '', ExceptedResolution: '', TicketCategory: '', Product: '',ItemName:'', Priority: '', CCUsers: [] });
                    vm.FormSchema[0].Data[0].value = response.data.ticket.statusId;
                    vm.Mainleveldiv[0].StatusId = response.data.ticket.statusId;
                    vm.FormSchema[0].Data[1].value = response.data.ticket.expectedResolutionDate;
                    vm.isSupportTicket = response.data.ticket.IsSupportTicket
                    vm.onBehalfConsumerId = response.data.ticket.onBehalfConsumerId;
                    vm.Mainleveldiv[0].ExceptedResolution = response.data.ticket.expectedResolutionDate;
                    if (!vm.isBlank(response.data.ticket.ticketCategoryId)) {
                        vm.FormSchema[0].Data[3].value = response.data.ticket.ticketCategoryId;
                        vm.Mainleveldiv[0].TicketCategory = response.data.ticket.ticketCategoryId;
                    }
                    if (!vm.isBlank(response.data.ticket.productId)) {
                        vm.FormSchema[0].Data[4].value = response.data.ticket.productId;
                        vm.Mainleveldiv[0].Product = response.data.ticket.productId;
                        vm.GetItemNameByCatalogueId(response.data.ticket.productId);
                    }  
                    if (!vm.isBlank(response.data.ticket.itemId)) {
                        vm.FormSchema[0].Data[5].value = response.data.ticket.itemId;
                        vm.Mainleveldiv[0].ItemName = response.data.ticket.itemId;
                      
                    }           
                    if (!vm.isBlank(response.data.ticket.expectedResolutionDate)) {                        
                        vm.FormSchema[0].Data[1].value = response.data.ticket.expectedResolutionDate;                        
                    }                    
                    if (!vm.isBlank(response.data.ticket.isTicketDelay)) {                        
                        vm.GetDelayTicket();
                        vm.FormSchema[0].Data[8].validationRules.required=true;
                        vm.FormSchema[0].Data[8].value = response.data.ticket.isTicketDelay;
                        vm.isDelayResponse=response.data.ticket.isTicketDelay;
                        vm.FormSchema[0].Data[7].value=1;
                        vm.FormSchema[0].Data[8].visibility = true;
                    }else{                        
                        vm.FormSchema[0].Data[7].value="";
                        vm.FormSchema[0].Data[8].visibility = false;
                        vm.FormSchema[0].Data[8].validationRules.required=false;
                    }
                    vm.FormSchema[0].Data[6].value = response.data.ticket.priorityId;
                    vm.Mainleveldiv[0].Priority = response.data.ticket.priorityId;
                    var ccuser = response.data.ticket.ccUser;
                    if (!vm.isBlank(ccuser)) {
                        var bindCCUser = [];
                        vm.ccOption = vm.CCUserList.filter(f => ccuser.indexOf(f.value) > -1);
                        vm.ccOption.forEach((item, index) => {
                            bindCCUser.push({
                                value: item.value,
                                label: item.name
                            })
                        });
                        vm.FormSchema[0].Data[2].value = bindCCUser;
                        vm.Mainleveldiv[0].CCUsers = bindCCUser;
                    }

                    if(response.data.ticket.status == "TICKET_CLOSEDLOCKED"){
                        vm.FormSchema[0].Data[0].disabled = true;
                        vm.FormSchema[0].Data[1].disabled = true;
                        vm.FormSchema[0].Data[2].disabled = true;
                        vm.FormSchema[0].Data[3].disabled = true;
                        vm.FormSchema[0].Data[4].disabled = true;
                        vm.FormSchema[0].Data[6].disabled = true;
                        if(vm.buttons[0].class == 'btn btn-success save')
                        {
                            vm.buttons[0].class = 'btn btn-success save disabled';
                        }
                    }
                }
            })
        },
        GetStatusList: function () {
            var vm = this;
            var params = `statusType=${"Ticketing"}&&hasglobal=${false}`;
             DataService.GetStatusList(params).then(async (response) => {
                if (response.data.length > 0) {
                    vm.statusList = [];
                    vm.statusList = response.data;
                    (vm.FormSchema)[0].Data[0].config.options = []
                    vm.statusList.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[0].config.options.push({
                            value: item.STATUS_ID,
                            name: item.STATUS
                        })
                    })
                }
            });
        },
        GetCCUserList: function () {
            var vm = this;
            var params = `id=&moduleName=Ticketing&type=CC_USER_LIST&search=&refId=`;
            DataService.GetDDLData(params).then(async (response) => {
                if (response.data.DATA.length > 0) {
                    var json = response.data.DATA;
                    vm.CCUserList = response.data.DATA;
                    if (json != null) {
                        response.data.DATA.forEach((item, index) => {
                            (vm.FormSchema)[0].Data[2].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                }
            });
        },
        GetCategoryForTicket: function () {
            var vm = this;
            var params = `categoryTypeId=${'TICKET_CATEGORY'}&is_Global=${false}&showActiveStatus=${true}`;
            DataService.GetDDLCategoryForTicket(params).then(async (response) => {
                if (response.data.length > 0) {
                    vm.CategoryList = [];
                    vm.CategoryList = response.data;
                    (vm.FormSchema)[0].Data[3].config.options = [];
                    vm.CategoryList.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[3].config.options.push({
                            value: item.value,
                            name: item.name
                        })
                    })
                }

            });
        },
        GetProductsList: function (type) {
            var vm = this;
            var funcType='';
            if(type){
                funcType ='PRODUCT';
            }
            else{
                funcType ='ASSET_PRODUCT_NAME_FOR_TICKET';
            }
            var params = `id=&moduleName=Ticketing&type=${funcType}&search=&refId=`;
            DataService.GetDDLData(params).then(async (response) => {
                var json = response.data;
                if (!vm.isBlank(json)) {
                    if (response.data.DATA.length > 0) {
                        vm.productList = response.data.DATA;
                        vm.productList.forEach((item, index) => {
                            (vm.FormSchema)[0].Data[4].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                        vm.$refs.DataLoaded.UpdateKeyValue();
                    }
                }
              
            });
        },
        GetItemNameByCatalogueId: function (catalogueId) {
            var vm = this;
            vm.$refs.DataLoaded.updateProperty("ItemName", "config.options",[]);
            vm.$refs.DataLoaded.updateProperty("ItemName", "value","");
            vm.$refs.DataLoaded.UpdateKeyValue();
            var params = `id=${catalogueId}&moduleName=Ticketing&type=PRODUCT_UNIQUE_NAME_BY_CATALOGUE_ID&search=&refId=${vm.onBehalfConsumerId}`;
             DataService.GetDDLData(params).then(async (response) => {
                var json = response.data;
                if (json != null && json != '') {
                    if (response.data.DATA.length > 0) 
                    {
                        vm.$refs.DataLoaded.updateProperty("ItemName", "config.options",response.data.DATA);
                        vm.$refs.DataLoaded.UpdateKeyValue();
                    }
                }
            });
        },
        // GetProductsList: function () {
        //     var vm = this;
        //     DataService.GetProductsList().then(async (response) => {
        //         if (response.data.length > 0) {
        //             vm.productList = response.data;
        //             vm.productList.forEach((item, index) => {
        //                 (vm.FormSchema)[0].Data[4].config.options.push({
        //                     value: item.value,
        //                     name: item.name
        //                 })
        //             })
        //         }
        //     });
        // },
        GetPrioritybyCompanyId: function () {
            var vm = this;
            DataService.GetPrioritybyCompanyId().then(async (response) => {
                if (response.data.length > 0) {
                    vm.priorityList = response.data;
                    vm.priorityList.forEach((item, index) => {
                        (vm.FormSchema)[0].Data[6].config.options.push({
                            value: item.prioritY_ID,
                            name: item.prioritY_NAME
                        })
                    })
                }
            });
        },
        onChangeDropdown: async function (e) {
            ////debugger;
            var vm = this;
            var dropName = e.target.name;
            var dropValue = e.target.value;
            if (dropName == "Product") {
                vm.isProductChanged = 1;
                vm.GetItemNameByCatalogueId(dropValue);
            }
            else if (dropName == "Priority") {
                vm.isPriorityChanged = 1;
            }
            else if (dropName == "TicketCategory") {
                vm.isCategoryChanged = 1;
            }
            else if (dropName == "Status") {
                vm.isStatusChanged = 1;
            }
            
        },
        onChangeRadio:async function (params) {
            var vm = this;
            if(params.target.getAttribute('data-value') == "1"){  
                vm.FormSchema[0].Data[8].validationRules.required=true;
                var params = `id=&moduleName=Ticketing&type=Ticket_Is_Delay&search=&refId=`;
                DataService.GetDDLData(params).then(async (response) => {
                    if (response.data.DATA.length > 0) {
                        var json = response.data.DATA;
                        vm.FormSchema[0].Data[8].config.options=[];
                        if (json != null) {
                            response.data.DATA.forEach((item, index) => {
                                vm.FormSchema[0].Data[8].config.options.push({
                                    value: item.value,
                                    name: item.name
                                })
                            });
                            vm.FormSchema[0].Data[8].visibility=true;
                        }
                    }
                });
            }
            else{                
                vm.FormSchema[0].Data[8].visibility=false;
                vm.FormSchema[0].Data[8].validationRules.required=false;
                vm.FormSchema[0].Data[8].value="";
            }
        },
        GetDelayTicket:async function () { 
            var vm = this;
            var params = `id=&moduleName=Ticketing&type=Ticket_Is_Delay&search=&refId=`;
            DataService.GetDDLData(params).then(async (response) => {
                if (response.data.DATA.length > 0) {
                    var json = response.data.DATA;
                    if (json != null) {
                        response.data.DATA.forEach((item, index) => {
                            vm.FormSchema[0].Data[8].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        });
                        vm.FormSchema[0].Data[8].visibility=true;
                        vm.$refs.DataLoaded.UpdateKeyValue();
                    }
                }
            });
        },
        onSubmit: function (formfields, val) {            
            var vm = this;
            var CCUsers = '';
            var i = 0;
            for (i = 0; i < vm.FormSchema[0].Data[2].value.length; i++) {
                if (i == 0) {
                    CCUsers = vm.FormSchema[0].Data[2].value[i].value;
                } else {
                    CCUsers = CCUsers + "," + vm.FormSchema[0].Data[2].value[i].value;
                }
            }
            var postJSON = {
                ticketId: vm.TicketId,
                statusId: vm.FormSchema[0].Data[0].value,
                userID: vm.user_id,
                productId: vm.isBlank(vm.FormSchema[0].Data[4].value) !== true ? vm.FormSchema[0].Data[4].value : null,
                ccOption: vm.isBlank(CCUsers) !== true ? CCUsers : null,
                ticketCategory: vm.isBlank(vm.FormSchema[0].Data[3].value) !== true ? vm.FormSchema[0].Data[3].value : null,
                priorityId: vm.isBlank(vm.FormSchema[0].Data[6].value) !== true ? vm.FormSchema[0].Data[6].value : null,
                expectedResolutionDate: vm.isBlank(vm.$options.filters.formatDateDDMMYYToMMDDYYY(vm.FormSchema[0].Data[1].value)) != true ? vm.$options.filters.formatDateDDMMYYToMMDDYYY(vm.FormSchema[0].Data[1].value) : null,
                isProductChanged: vm.isBlank(vm.isProductChanged) !== true ? vm.isProductChanged : 0,
                isETAChanged: vm.isBlank(vm.$options.filters.formatDate(vm.FormSchema[0].Data[1].value)) !== true ? 1 : 0,
                isStatusChanged: vm.isBlank(vm.isStatusChanged) !== true ? vm.isStatusChanged : 0,
                isCategoryChanged: vm.isBlank(vm.isCategoryChanged) !== true ? vm.isCategoryChanged : 0,
                isPriorityChanged: vm.isBlank(vm.isPriorityChanged) !== true ? vm.isPriorityChanged : 0,
                isSupportTkt: vm.isSupportTicket,
                ticketOpenDate: vm.isBlank(vm.$options.filters.formatDateDDMMYYToMMDDYYY(vm.FormSchema[0].Data[1].value)) !== true ? vm.$options.filters.formatDateDDMMYYToMMDDYYY(vm.FormSchema[0].Data[1].value) : null,
                isdelayTicket: vm.FormSchema[0].Data[8].value !=""?vm.FormSchema[0].Data[8].value:0,
                itemName: vm.isBlank(vm.FormSchema[0].Data[5].value) !== true ? vm.FormSchema[0].Data[5].value : null,
            };
            vm.$parent.ticketIds = vm.TicketId;            
            var StatusId = postJSON.statusId == null ? '' : postJSON.statusId;
            var ExceptedResolutionDate = postJSON.expectedResolutionDate == null ? '' : postJSON.expectedResolutionDate;
            var TicketCategory = postJSON.ticketCategory == null ? '' : postJSON.ticketCategory;
            var ProductId = postJSON.productId == null ? '' : postJSON.productId;
            var ItemName = postJSON.itemName == null ? '' : postJSON.itemName;
            var PriorityId = postJSON.priorityId == null ? '' : postJSON.priorityId;
            var ccOption = postJSON.ccOption == null ? '' : postJSON.ccOption;
            var dataValue = '';
            var CCOptions = 0;
            vm.Mainleveldiv[0].CCUsers.forEach((itm, index) => {
                if (index == 0) {
                    dataValue = itm.value;
                }
                else {
                    dataValue += ',' + itm.value;
                }
            })
            var testDataValue = dataValue;
            function arraysAreEqual(ccOption, testDataValue) {
                if (ccOption.length !== testDataValue.length) {
                    return false;
                }

                for (let i = 0; i < ccOption.length; i++) {
                    if (ccOption[i] !== testDataValue[i]) {
                        return false;
                    }
                }
                return true;
            }
            if (arraysAreEqual(ccOption, testDataValue)) {
                CCOptions = 1;
            }
            var date1 = '';
            var date2 = '';
            if (vm.Mainleveldiv[0].ExceptedResolution == '') {
                date1 = '';
            } else {
                date1 = vm.$options.filters.formatDateDDMMYYToMMDDYYY(vm.Mainleveldiv[0].ExceptedResolution);
            }
            if (ExceptedResolutionDate == '') {
                date2 = '';
            } else {
                date2 = ExceptedResolutionDate;
            }
            if (date1 != date2) {
                vm.IsChangeData = 0;
            }
            if (vm.Mainleveldiv[0].StatusId != StatusId) {
                vm.IsChangeData = 0;
            }
            else if (CCOptions != 1) {
                vm.IsChangeData = 0
            }
            else if (vm.Mainleveldiv[0].TicketCategory != TicketCategory) {
                vm.IsChangeData = 0;
            }
            else if (vm.Mainleveldiv[0].Product != ProductId && vm.isAssetPermission == true) {
                vm.IsChangeData = 0;
            }
            else if (vm.Mainleveldiv[0].ItemName != ItemName && vm.isAssetPermission == true) {
                vm.IsChangeData = 0;
            }
            else if (vm.Mainleveldiv[0].Priority != PriorityId) {
                vm.IsChangeData = 0;
            }
            else if(vm.FormSchema[0].Data[8].value != vm.isDelayResponse){
                vm.IsChangeData = 0;
            }
            if (vm.IsChangeData == 0) {
                var objectPostString = JSON.stringify(postJSON);
                vm.isLoading = true;
                DataService.TicketUpdate(objectPostString).then((response) => {
                    try {
                        if (response.data != null && response.data != "" && response.data.status == "Success") {
                            vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("Ticket")]), "success", true, vm.$t("Alert"));
                            vm.Close('Updated');
                        }
                        else {
                            vm.Close('Updated');

                        }
                    } catch (exinner) {
                        return HandleErrorOccured(exinner, 'Ticket');
                    }
                });
            } 
            else {
                vm.ShowAlert(vm.$t('PleaseChangeAnyRecordsForFurther'), 'warning', true, vm.$t('Alert'));
            }
        },
        Close: function (type) {
            var vm = this;
            vm.FormSchema[0].Data[0].value = null;
            vm.FormSchema[0].Data[1].value = null;
            vm.FormSchema[0].Data[2].value = null;
            vm.FormSchema[0].Data[3].value = null;
            vm.FormSchema[0].Data[4].value = null;
            vm.FormSchema[0].Data[6].value = null;
            vm.$parent.isShowTicketUpdate = false;
            if(type == 'Updated'){
                document.getElementById('tab-ticketdetails').click();
                 vm.callbackfunction();
            }
            vm.isLoading = false;
        }
    }
}
</script>