<template>
    <div class="listing">       
         <div id="accordion" class="w-100">
            <div class="card" v-for="(groupItem, key, index) in groupByDate">
                <div class="card-header">
                    <a :class="{ 'card-link collapsed': index > 1, 'card-link': index <= 1 }" data-toggle="collapse"
                        :href="'#collapseOneThread' + index">
                        <div class="conversation-date heading-border"><span>{{ $t(key) }}</span></div>
                    </a>
                </div>
                <div>
                    <div :id="'collapseOneThread' + index"
                        :class="{ 'collapse': index > 1, 'collapse show': index <= 1 }">
                        <div class="card-body">
                            <div class="conversation-main">

                                <template v-for="(item, index) in groupItem" v-if="(item.statusCode == 'TICKET_REPLY_DRAFT' && item.threadCreatedBy == UserId) || item.statusCode != 'TICKET_REPLY_DRAFT'">
                                    <div class="conversation-time">
                                        <span>{{ formatTime(item.createdAt) }}</span>
                                    </div>
                                    <div class="conversation-box-con">
                                        <div class="conversation-box">
                                            <div class="name-circle text-white light-yellow"><em class="fa fa-file"
                                                    aria-hidden="true"
                                                    style="font-size: 18px; margin-top: 18px !important"></em></div>
                                            <div class="conversation-header addednote-ticket">
                                                <span>
                                                    <span class="sender-name">{{ item.actionPerformedByName }}</span>
                                                    <span class="sender-department">({{ item.actionPerformedByDeptName
                                                        }})</span>
                                                </span>
                                                <span class="header-action"
                                                    v-if="item.referenceId > 0 && item.currentStatus == 'TICKET CONCLUSION DRAFT'">
                                                    <!-- <a id="_aSplit" @click="SplitTicket(item)" title=""
                                                        :data-threadid="item.ticketThreadId" href="javascript:;"
                                                        class="round-icon-split round-icon split"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to Split ticket"><em
                                                            class="fa fa-code-fork"
                                                            style="transform: rotate(90deg);"></em></a> -->
                                                    <a :id="item.ticketAttachmentId" @click="DownloadAttachment(item)"
                                                        v-if="item.ticketAttachmentId > 0"
                                                        class="btn-primary downloadAttachement round-icon-split round-icon split"
                                                        :title="$t('ClickHereDownloadAttachment')"
                                                        :alt="$t('DownloadFile')" href="javascript:;"
                                                        :value="item.ticketAttachmentId"
                                                        :data-isSupportTicket="item.isSupportTicket">
                                                        <em class="fa fa-download"></em>
                                                    </a>
                                                    <a class="editTicketThreadConclusion btn-success round-icon"
                                                        @click="EditTicketThreadConclusion(item)" href="javascript:;"
                                                        title="" data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to edit ticket conclusion"
                                                        aria-describedby="tooltip90021">
                                                        <em class="fa fa-pencil"></em>
                                                    </a>
                                                </span>
                                                <span class="header-action"
                                                    v-if="item.referenceId > 0 && item.currentStatus == 'CONCLUSION'">
                                                    <!-- <a id="_aSplit" @click="SplitTicket(item)" title=""
                                                        :data-threadid="item.ticketThreadId" href="javascript:;"
                                                        class="round-icon-split round-icon split"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to Split ticket"><em
                                                            class="fa fa-code-fork"
                                                            style="transform: rotate(90deg);"></em></a> -->
                                                     <a :id="item.ticketAttachmentId" @click="DownloadAttachment(item)"
                                                        v-if="item.ticketAttachmentId > 0"
                                                        class="btn-primary downloadAttachement round-icon-split round-icon split"
                                                        :title="$t('ClickHereDownloadAttachment')"
                                                        :alt="$t('DownloadFile')" href="javascript:;"
                                                        :value="item.ticketAttachmentId"
                                                        :data-isSupportTicket="item.isSupportTicket">
                                                        <em class="fa fa-download"></em>
                                                    </a>
                                                    <a class="anconclusiondetails bg-primary round-icon"
                                                        @click="ViewThreadConclusion(item)" href="javascript:;" title=""
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to edit ticket conclusion"
                                                        aria-describedby="tooltip90021">
                                                        <em class="fa fa-eye text-white"></em>
                                                    </a>
                                                </span>
                                                <span class="header-action"
                                                    v-if="item.referenceId > 0 && item.currentStatus == 'CLAIM DRAFT'">
                                                    <a :id="item.ticketAttachmentId" @click="DownloadClaimAttachment(item)"
                                                        v-if="item.ticketAttachmentId > 0"
                                                        class="btn-primary downloadAttachement round-icon-split round-icon split"
                                                        :title="$t('ClickHereDownloadAttachment')"
                                                        :alt="$t('DownloadFile')" href="javascript:;"
                                                        :value="item.ticketAttachmentId"
                                                        :data-isSupportTicket="item.isSupportTicket">
                                                        <em class="fa fa-download"></em>
                                                    </a>
                                                    <a href="javascript:;" @click="EditClaim(item)"
                                                        class="btn-success round-icon clseditclick"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to edit ticket claim">
                                                        <em class="fa fa-pencil"></em>
                                                    </a>
                                                    <a href="javascript:;" @click="DeleteTicketClaim(item)"
                                                        class="btn-danger round-icon clsdeleteticketclaim"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to delete Ticket Claim">
                                                        <em class="fa fa-trash"></em>
                                                    </a>
                                                </span>
                                                <span class="header-action"
                                                    v-if="item.statusCode == 'TICKET_REPLY_DRAFT'">
                                                    <a :id="item.ticketAttachmentId" @click="DownloadAttachment(item)"
                                                        v-if="item.ticketAttachmentId > 0"
                                                        class="btn-primary downloadAttachement round-icon-split round-icon split"
                                                        :title="$t('ClickHereDownloadAttachment')"
                                                        :alt="$t('DownloadFile')" href="javascript:;"
                                                        :value="item.ticketAttachmentId"
                                                        :data-isSupportTicket="item.isSupportTicket">
                                                        <em class="fa fa-download"></em>
                                                    </a>
                                                    <a href="javascript:;" @click="EditDraftTicket(item)"
                                                        class="btn-success round-icon clseditclick"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to edit ticket claim">
                                                        <em class="fa fa-pencil"></em>
                                                    </a>
                                                    <a href="javascript:;" @click="DeleteDraftedReply(item)"
                                                        class="btn-danger round-icon clsdeleteticketclaim"
                                                        data-toggle-tooltip="tooltip"
                                                        data-original-title="Click here to delete Ticket Claim">
                                                        <em class="fa fa-trash"></em>
                                                    </a>
                                                </span>
                                                <span class="header-action" v-if="item.statusCode == 'TICKET_FEEDBACK'">
                                                    <a href="javascript:;" class="anccondetails bg-primary round-icon"
                                                        data-toggle-tooltip="tooltip" @click="ViewFeedback(item)"
                                                        data-original-title="Click here to view ticket feedback">
                                                        <em class="fa fa-eye"></em>
                                                    </a>
                                                    <a :id="item.ticketAttachmentId" @click="DownloadAttachment(item)"
                                                        v-if="item.ticketAttachmentId > 0"
                                                        class="btn-primary downloadAttachement round-icon-split round-icon split"
                                                        :title="$t('ClickHereDownloadAttachment')"
                                                        :alt="$t('DownloadFile')" href="javascript:;"
                                                        :value="item.ticketAttachmentId"
                                                        :data-isSupportTicket="item.isSupportTicket">
                                                        <em class="fa fa-download"></em>
                                                    </a>
                                                </span>
                                           
                                            </div>
                                            <div class="conversation-content addednote-ticket">
                                                <p>{{ SetMessage(item) }}</p>                                               
                                                <div class="addednote-ticket-content"
                                                    v-if="item.threadDescription != null && item.threadDescription.length > 0">
                                                    <div class="col-12 p-0 notesdata">
                                                        <div class="readmore">
                                                            <span v-html="item.threadDescription"></span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div v-if="showTicketFeedback && item.statusCode == 'TICKET_FEEDBACK' " class="row">                                                    
                                                    <div class="col-sm-12 col-md-12 col-lg-12">
                                                        <div class="heading-border">
                                                            <h5 class="h5  mb-3">
                                                                <span>{{ $t('Feedback') }} </span>
                                                            </h5>
                                                        </div>
                                                    </div>
                                                    <div v-for="(record, index) in listAnswers" :key="index" class="col-sm-12 col-md-12 col-lg-12"> 
                                                        <div class="row" id="divfeedbackTicketdata">
                                                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 feedback-conversation-content">
                                                                <div class="form-group">
                                                                    <label>{{ record.questionText }}:</label>                                                               
                                                                    <template v-if="record.answerType === 'Comments'">
                                                                        <textarea v-model="record.feedbackAnswer"
                                                                            class="txtFeedbackAnswer textarea-large"
                                                                            :maxlength="2000"
                                                                            @input="handleInput"></textarea>                                                                  
                                                                    </template>
                                                                    <template v-else-if="record.answerType === 'Objective'">
                                                                        <div class="objectiveTypeDiv">
                                                                            <div class="form-group">
                                                                                <div v-for="(item, i) in record.optionValue.split('_')"
                                                                                    :key="i"
                                                                                    class="custom-control custom-radio custom-control-inline">
                                                                                    <input
                                                                                        class="custom-control-input IsRuleApllicable dynamic"
                                                                                        type="radio"
                                                                                        :id="'customcheckbox' + item + objectiveCount"
                                                                                        :name="'PointScale' + objectiveCount"
                                                                                        :value="item" :checked="record.feedbackAnswer === item" disabled>
                                                                                    <label class="custom-control-label"
                                                                                        :for="'customcheckbox' + item + objectiveCount">
                                                                                        {{ item === 'VeryGood' ? 'Very Good'
                                                                                            :
                                                                                        item }}</label>
                                                                                </div>
                                                                            </div>                                                                        
                                                                        </div>
                                                                    </template>
                                                                    <template v-else>
                                                                        <div>
                                                                            <span class="crating rating" id="ratingType">
                                                                                <i v-for="s in 5" :key="4"
                                                                                    class="fa fa-star"
                                                                                    :class="{ 'text-warning': s <= record.feedbackAnswer }"
                                                                                    :value="s"></i>
                                                                            </span>                                                                      
                                                                        </div>
                                                                    </template>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                            </div>
                                            <div id="feedbacklist" class="splitticketboxfeedbox"
                                                v-if="ShowConclusionDetail && item.referenceId > 0 && item.currentStatus == 'CONCLUSION'">
                                                <div class="splitticketcontainer">
                                                    <div class="conclusion-ticket col-lg-12 p-0 mt-3">
                                                        <div class="col-sm-12 col-md-12 col-lg-12 p-0">
                                                            <div class="heading-border">
                                                                <h5 class="h5 mb-2">
                                                                    <span>Conclusion Created by</span> -
                                                                    {{ item.actionPerformedByName }}
                                                                    at {{
                                                                        $options.filters.formatDateTime(item.createdAt) }}
                                                                </h5>
                                                            </div>
                                                        </div>
                                                        <div class="conclusion-ticket-content mb-2 col-12 p-0">
                                                            <strong class="mr-2">Root Cause:</strong> {{ item.rootCause
                                                            }}
                                                        </div>
                                                        <div class="conclusion-ticket-content mb-2 col-12 p-0">
                                                            <strong class="mr-2">Corrective Action:</strong>
                                                            {{ item.correctiveAction }}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>

                                        <div class="conversation-box"
                                            v-if="(showMergeTicket && (item.statusCode === 'TICKET_CREATED' && item.currentStatus.includes('|MERGE_FROM|')) || (item.statusCode === 'TICKET_MERGE' && item.currentStatus.includes('|')))">                                           
                                            <div class="name-circle text-white light-green"><em class="fa fa-random"
                                                    aria-hidden="true"
                                                    style="font-size: 18px; margin-top: 18px !important"></em>
                                            </div>
                                            <div class="conversation-header">
                                                <span>
                                                    <span class="sender-name">{{ item.actionPerformedByName }}</span>
                                                    <span class="sender-department">({{ item.actionPerformedByDeptName
                                                        }})</span>
                                                </span>
                                            </div>                                           
                                            <div class="conversation-content">
                                                <p class="listing">
                                                    <strong>MergeTicket
                                                        <span v-for="(mVal, mIndex) in item.mergedValue"><a :href="'/Ticketing/Manage/'+ encodeURIComponent(mVal.value)"
                                                            target="_blank"> #{{  mVal.name }} </a>
                                                            <span v-if="mIndex !== item.mergedValue.length - 1">, </span>
                                                        </span>
                                                        <span></span>
                                                    </strong>
                                                </p>
                                            </div>

                                        </div>
                                    </div>
                                </template>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <div class="col-sm-12 col-md-12 text-center col-lg-12 mt-2 float-left p-0" v-if="NoRecords">
                <span class="text-danger no-record">{{ $t('NoRecordfound') }}</span>
            </div>
        </div>
    </div>
</template>

<script>
import DataServices from "@/services/DataService";
export default {
    props: {
        TicketThreads: {
            type: Array,
            required: true
        },       
        ticketId:{
              type:Number,
              required: true
        },
        feedbackAnswer:{
            type: String,
            required: true
        }
    },
    data() {
        return {
            ThreadsList: [],
            UserType: null,
            UserId: null,
            companyId: null,
            NoRecords: false,
            // MergeTicketId: '',
            showMergeTicket: false,
            showTicketFeedback: false,
            ShowConclusionDetail: false,
            feedbackAnswers: '',
            // MergeTicketIdUrl: '',
            TicketNumberData:'',
            UserName: ''
            
        }

    },
    computed: {
        groupByDate() {
            var vm = this;
            let groups = {};
            vm.TicketThreads.forEach(item => {
                let date = item.createdAt.substring(0, 10);
                if (groups[date]) {
                    groups[date].push(item);
                } else {
                    groups[date] = [item];
                }
            });

            return groups;
        }
    },    
    created() {
        //debugger
        var vm = this;
        vm.UserId = vm.GetUserInfo.ID;
        vm.companyId = this.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.feedbackAnswers = this.feedbackAnswer;
        vm.UserName = vm.GetUserInfo.Name;
    },
    methods: {
        DownloadClaimAttachment(item) {
            var vm = this;
            // vm.isLoading = true;
            var privilegeParams = `controller=Ticketing&action=DownloadClaimFile`;
            DataServices.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    var param = `filePath=${item.fileSrc}&fileName=${item.fileName}`;
                    DataServices.DownloadFile(param).then(function (response) {
                        // vm.isLoading = false;
                        const byteData = response.data;
                        const fileURL = `data:${((JSON.parse(item.fileMime)).ContentType)};base64,${byteData}`;
                        var fileLink = document.createElement('a');
                        fileLink.href = fileURL;
                        fileLink.setAttribute('download', item.fileName);
                        document.body.appendChild(fileLink);
                        fileLink.click();
                    });
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
            });
           
        },
        DownloadAttachment(item) {
            var vm = this;
            vm.isLoading = true;
            var param = `filePath=${item.fileSrc}&fileName=${item.fileName}`;
            DataServices.DownloadFile(param).then(function (response) {
                vm.isLoading = false;
                const byteData = response.data;
                const fileURL = `data:${((JSON.parse(item.fileMime)).ContentType)};base64,${byteData}`;
                var fileLink = document.createElement('a');
                fileLink.href = fileURL;
                fileLink.setAttribute('download', item.fileName);
                document.body.appendChild(fileLink);
                fileLink.click();
            });
        },
        EditTicketThreadConclusion(item) {
            var vm = this;
            vm.$parent.FormConclusionData = [];
            vm.$parent.FetchData();
            vm.$parent.isShowTicketConclusion = true;
            vm.$parent.FormConclusionData.push({
                conclusionid: item.referenceId,
                thredid: item.currentStatus,
                TicketId: item.ticketId,
                rootcause: item.rootCause,
                correctiveaction: item.correctiveAction
            });
            vm.$parent.GetNewData();
        },
        SplitTicket(item) {
            var vm = this;
            if (item.priviousStatus == 'CLOSED' || item.priviousStatus == 'CLOSED AND LOCKED' || item.priviousStatus == 'CANCELLED') {
                vm.ShowAlert(vm.$t('SorryThetickethavebeenclosed'), 'warning', true, vm.$t('Alert'));
                return false;
            }
        }, 
        ViewThreadConclusion(item) {
            var vm = this;
            if (item.referenceId > 0 && item.currentStatus == 'CONCLUSION') {
                vm.ShowConclusionDetail = vm.ShowConclusionDetail ? false : true;
            }
        },
        ViewFeedback(item) {
            //debugger
            var vm = this;
            if(vm.showTicketFeedback)
            {
                vm.showTicketFeedback = false;
            }
            else{
                vm.showTicketFeedback = true;
            }
            vm.FetchTicketAnswers();           
        },
        EditClaim(item) {
            var vm = this;
            vm.$parent.FormClaimData = [];
            vm.$parent.FetchData();
            vm.$parent.FormClaimData.push({
                ClaimId: item.referenceId,
                thredid: item.currentStatus,
                TicketId: item.ticketId
            });
            vm.$parent.GetEditClaimData();
        },
        EditDraftTicket(item) {
            //debugger
            var vm = this;
            vm.$parent.DraftTicketData = [];
            vm.$parent.FetchData();
            vm.$parent.DraftTicketData.push({
                thredid: item.ticketThreadId,
                threadDescription: item.threadDescription,
                TicketId: item.ticketId
            });
            vm.$parent.GetEditDraftReply();
        },
        DeleteTicketClaim: function (item) {
            var vm = this;
            //vm.isLoading=true;
            var param = 'controller=Ticketing&action=DeleteClaimFile';
            DataServices.CheckPrivilege(param).then(function (response) {
                if (response.data) {
                    vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Claim")), function () {
                        vm.isLoading = true;
                        var postJSON = {
                            ids: item.referenceId,
                            companyId: vm.companyId,
                            userId: vm.UserId,
                            moduleName: "Ticketing",
                            refCode: "TALYGEN_TICKET_CLAIM"
                        };
                        var objectPostString = JSON.stringify(postJSON);
                        DataServices.deleteActivityData(objectPostString).then(response => {
                            var box = "";
                            vm.isLoading = false;
                            if (response.data[0].Status == "Success") {
                                document.getElementById('tab-cliam').click();
                                // vm.$parent.GetClaimData();
                                box = vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Claim')]), "Success", true, vm.$t('Alert'));
                            }
                            else {
                                box = vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Claim')]), "failure", true, vm.$t('Alert'));
                            }
                            vm.$emit('close');
                        });
                    });
                }
                else
                {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "warning", true, vm.$t("Alert"));
                }
            });            
        },
        DeleteDraftedReply: function (item) {
            //debugger
            var vm = this;
            //vm.isLoading=true;
            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Claim")), function () {
                vm.isLoading = true;
                var postJSON = {
                    threadId: item.ticketThreadId,
                    ticketId: item.ticketId,
                    attachementFor: "DELETEDRAFTREPLY"
                };
                var objectPostString = JSON.stringify(postJSON);
                DataServices.DeleteDraftedReply(objectPostString).then(response => {
                    var box = "";
                    vm.isLoading = false;
                    if (response.data.status == "Success") {
                        vm.$parent.FetchData();
                        box = vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Draft Reply')]), "Success", true, vm.$t('Alert'));
                    }
                    else {
                        box = vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Draft Reply')]), "failure", true, vm.$t('Alert'));
                    }
                    vm.$emit('close');
                });
            });
        },        
        FetchTicketAnswers: async function () {
            debugger
            var vm = this;
            var url = `departmentId=${this.TicketDepartmentId == undefined ? 0 : this.TicketDepartmentId}&ticketId=${this.ticketId}&ticketStatus= 'Closed and Locked'`;
            await DataServices.TicketFeedbackAnswersList(url).then(function (response) {               
                vm.listAnswers = response.data.ListAnswers;
            })
        },
        SetMessage: function (item) {
            var vm = this;
            var message = '';
            if (item.statusCode == 'TICKET_TRANSFER' && item.currentStatus == item.priviousStatus && vm.UserType != 'CA') {
                var statusCode = "TICKET_TRANSFER";
                if (item.threadType == 'A') {
                    statusCode = 'TICKET_ASSIGNED';
                }
                if (item.threadCreatedBy == vm.UserId && vm.UserType != 'CA' && vm.UserType != 'SA') {
                    if (item.ticketCreatedBy == vm.UserId && vm.UserType != 'CA' && vm.UserType != 'SA') {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.departmentName + " " + vm.$t('To') + " " + (item.currentStatus == '' ? item.departmentName : item.currentStatus);
                    }
                    else {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.actionPerformedByName + " " + vm.$t('To') + " " + (item.currentStatus == '' ? item.departmentName : item.currentStatus);
                    }
                }
                else {
                    if (vm.UserType != 'CA' && vm.UserType != 'SA') {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + (statusCode == 'TICKET_TRANSFER' ? item.actionPerformedByDeptName : item.actionPerformedByName) + " " + vm.$t('To') + " " + (statusCode == 'TICKET_TRANSFER' ? item.departmentName : item.currentStatus);
                    }
                    else if (item.currentStatus == '') {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.actionPerformedByName + " " + vm.$t('To') + " " + item.departmentName;
                    }
                    else {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.actionPerformedByName + " " + vm.$t('To') + " " + (item.currentStatus == '' ? item.departmentName : item.currentStatus);
                    }
                }
            }
            else if (item.statusCode == 'TICKET_TRANSFER' && item.priviousStatus.length > 0 && vm.UserType != 'CL') {
                var statusCode = "TICKET_TRANSFER";
                if (item.threadType == "A") {
                    statusCode = "TICKET_ASSIGNED";
                }
                var ChkName = '';
                if (item.actionPerformedByName != item.priviousStatus && item.priviousStatus != '') {
                    ChkName = vm.$t('From') + " " + item.priviousStatus;
                }
                if (item.currentStatus.toUpperCase() == item.priviousStatus.toUpperCase()) {
                    ChkName = '';
                }
                if (item.threadCreatedBy == vm.UserId && vm.UserType != 'CA' && vm.UserType != 'SA') {
                    if (item.ticketCreatedBy == vm.UserId && vm.UserType != 'CA' && vm.UserType != 'SA') {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.departmentName + " " + vm.$t('To') + " " + (item.currentStatus == '' ? item.departmentName : item.currentStatus) + " " + ChkName;
                    }
                    else {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + item.actionPerformedByName + " " + vm.$t('To') + " " + (item.currentStatus == '' ? item.departmentName : item.currentStatus) + " " + ChkName;
                    }
                }
                else {
                    if (vm.UserType != 'CA' && vm.UserType != 'SA') {
                        message = vm.$t(statusCode) + " " + vm.$t('By') + " " + statusCode == 'TICKET_TRANSFER' ? item.actionPerformedByDeptName : item.actionPerformedByName + " " + vm.$t('To') + " " + (statusCode == 'TICKET_TRANSFER' ? item.departmentName : item.currentStatus) + " " + ChkName;
