            else if (item.statusCode == "WORK_ORDER_FORMS_ACCEPT") {
                message = "Work Order Forms accepted " + vm.$t('By') + " " + item.actionPerformedByName;
            }
            else if (item.statusCode == "WORK_ORDER_FORMS_REJECT") {
                message = "Work Order Forms rejected " + vm.$t('By') + " " + item.actionPerformedByName;
            }
            else if(item.statusCode == "TICKET_DEALY_RESPONSE_UPDATED"){
                if(item.previousProduct != null && item.currentProduct != null){
                    message = "Ticket Delay Reason has been Updated by "+ item.actionPerformedByName +" "+ " From " + item.previousProduct + " To " + item.currentProduct
                } else if(item.currentProduct == null){
                    message = "Ticket Delay Reason has been Updated by "+ item.actionPerformedByName +" "+ " From " + item.previousProduct + " To Blank"
                } else if(item.previousProduct == null){
                    message = "Ticket Delay Reason has been Updated by "+ item.actionPerformedByName +" "+ " To " + item.currentProduct
                }               
            }
            else {
                message = vm.$t('AssignedTo') + " " + item.actionPerformedByName + " " + item.departmentName;
            }
            return message;
        }
    }
}
</script>

