<template>
    <div class="">
        <div class="row barrw" id="divfeedbackheader">
            <div class="col-sm-12 col-md-12 col-lg-12">
                <div class="heading-border">
                    <h5 class="h5  mb-3">
                        <span>{{ $t('Feedback') }} </span>
                    </h5>
                </div>
            </div>
        </div>
        <template v-if="listAnswers.length > 0">
            <div v-for="(record, index) in listAnswers" :key="index" class="col-sm-12 col-md-12 col-lg-12">
                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12">
                    <form @submit.prevent="saveFeedback">
                        <div class="row" id="divfeedbackTicketdata">
                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 feedback-conversation-content">
                                <div class="form-group">
                                    <label>{{ record.questionText }}:</label>
                                    <input type="hidden" v-model="record.questionId" class="QuestionId" />
                                    <input type="hidden" v-model="record.ticketFeedbackId" class="TicketFeedbackId" />
                                    <input type="hidden" v-model="record.ticketId" class="TicketId" />
                                    <template v-if="record.answerType === 'Comments'">
                                        <textarea v-model="feedbackAnswer" class="txtFeedbackAnswer textarea-large"
                                            :maxlength="2000" @input="handleInput"></textarea>

                                        <span name="Description"
                                            class="field-validation-valid text-danger field-validation-error"
                                            v-if="showError">{{ errorMessage }}</span>
                                    </template>
                                    <template v-else-if="record.answerType === 'Objective'">
                                        <div class="objectiveTypeDiv">
                                            <div class="form-group">
                                                <div v-for="(item, i) in record.optionValue.split('_')" :key="i"
                                                    class="custom-control custom-radio custom-control-inline">
                                                    <input class="custom-control-input IsRuleApllicable dynamic"
                                                        type="radio" :id="'customcheckbox' + item + objectiveCount"
                                                        :name="'PointScale' + objectiveCount" :value="item"
                                                        @click="objectiveTypeChange(item)">
                                                    <label class="custom-control-label"
                                                        :for="'customcheckbox' + item + objectiveCount">
                                                        {{ item === 'VeryGood' ? 'Very Good' : item }}</label>
                                                </div>
                                            </div>
                                            <input type="hidden" :id="'hddnObjectiveFeedbackAnswer' + record.questionId"
                                                :value="record.optionValue.split('_')[0]" />
                                        </div>
                                    </template>
                                    <template v-else>
                                        <div>
                                            <span class="crating rating" id="ratingType">
                                                <i v-for="s in 5" :key="s" class="fa fa-star"
                                                    :class="{ 'text-warning': s <= selectedRating }"
                                                    @click="selectRating(s)" :value="s"></i>
                                            </span>
                                            <input type="hidden" class="hdnStarRating" />
                                        </div>
                                    </template>
                                </div>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
            <div class="row flex-row-reverse mt-2">
                <div class="col-lg-6 text-right">
                    <button @click="saveFeedback" id="btnSaveFeedback" class="btn btn-success text-white">
                        <i class="fa fa-save pr-2"></i>{{ $t('Save') }}
                    </button>
                </div>
            </div>
        </template>
        <template v-else>
            <div class="d-block text-center text-danger border p-2 no-record">
                {{ $t('NoRecordfound') }}
            </div>
        </template>
    </div>
</template>


<script>
import DataServices from "@/services/DataService";

export default {
    props: {
        TicketId: {
            type: Number,
            required: true
        },
        TicketDepartmentId: {
            type: Number,
            required: true
        },
        TicketStatus: {
            type: String,
            required: true
        }
    },
    data() {
        return {
            errorMessage: "Answer is required.",
            selectedObjectiveValue: '',
            listAnswers: [],
            objectiveCount: 0,
            feedbackAnswer: '',
            selectedRating: 0,
            showError: false,
            Feedback: null,
        };
    },
    created: async function () {
        // debugger
        var vm = this;
        vm.user_id = this.GetUserInfo.ID;
        if (vm.TicketId > 0) {
            this.FetchTicketAnswers();
        }
    },
    methods: {
        objectiveTypeChange(item) {
            // debugger
            if (item) {
                this.selectedObjectiveValue = item;
            }
        },
        saveFeedback: async function () {
            //debugger;
            var vm = this;           
            var feedbackAnswers = [];
            vm.listAnswers.forEach(function (record) {
                var ticketId = record.ticketId;
                var ticketFeedbackId = record.ticketFeedbackId;
                var questionId = record.questionId;
                var threadId = record.threadId;                
                var feedbackAnswer;

                if (record.answerType === 'Comments') {
                    feedbackAnswer = document.querySelector('.txtFeedbackAnswer').value;
                    if (!feedbackAnswer.trim()) {
                        vm.showError = true;
                        return; 
                    }
                } else if (record.answerType === 'Objective') {
                    feedbackAnswer = vm.selectedObjectiveValue;
                } else {
                    feedbackAnswer = vm.selectedRating.toString();
                }               
                var ticketFeedbackAnswer = {
                    TicketId: ticketId,
                    TicketFeedbackId: ticketFeedbackId,
                    QuestionId: questionId,
                    FeedbackAnswer: feedbackAnswer
                };                
                feedbackAnswers.push(ticketFeedbackAnswer);
            });            
            var objectPostString = JSON.stringify({ ticketId: vm.TicketId, feedbackAnswers: feedbackAnswers });
            await DataServices.SaveUserFeedback(objectPostString).then(function (response) {
                if (response.data.status == 0) {
                    vm.$parent.isShowTicketFeedback = false;
                    vm.$parent.FetchData();
                    vm.ShowAlert(vm.$t("Ticket Feedback has been Successfully submitted", true, vm.$t("Alert")));
                }
            });
        },      
        
        FetchTicketAnswers: async function () {
            // debugger
            var vm = this;
            var url = `departmentId=${this.TicketDepartmentId == undefined ? 0 : this.TicketDepartmentId}&ticketId=${this.TicketId}&ticketStatus=${this.TicketStatus}`;
            await DataServices.TicketFeedbackQuestions(url).then(function (response) {
                debugger
                vm.listAnswers = response.data.ListAnswers;
            })
        },
        selectRating(s) {
            //debugger
            if (this.selectedRating === s) {
                this.selectedRating = 0;
            } else {
                this.selectedRating = s;
            }
            const hdnStarRating = document.querySelector('.hdnStarRating');
            if (hdnStarRating) {
                hdnStarRating.value = this.selectedRating;
            }
        }
    }
}
</script>


<style>
.text-warning {
    color: yellow;
    /* Change the color to yellow */
}

.textarea-large {
    width: 100%;
    height: 150px;
}

.field-validation-error {
    font-size: 80%;
}
</style>